package rt.core.org.apache.cxf.bus.managers;

@ ManagedResource ( componentName = "WorkQueueManager" , description = "The CXF manangement of work queues " , currencyTimeLimit = 15 , persistPolicy = "OnUpdate" , persistPeriod = 200 ) public class WorkQueueManagerImplMBeanWrapper implements ManagedComponent { static final String NAME_VALUE = "Bus.WorkQueueManager" ; static final String TYPE_VALUE = "WorkQueueManager" ; private WorkQueueManagerImpl wqManager ; private Bus bus ; public WorkQueueManagerImplMBeanWrapper ( WorkQueueManagerImpl wq ) { wqManager = wq ; bus = wq . getBus ( ) ; } @ ManagedOperation ( currencyTimeLimit = 30 ) public void shutdown ( boolean processRemainingWorkItems ) { wqManager . shutdown ( processRemainingWorkItems ) ; } public ObjectName getObjectName ( ) throws JMException { StringBuilder buffer = new StringBuilder ( ) ; buffer . append ( ManagementConstants . DEFAULT_DOMAIN_NAME ) . append ( ':' ) ; buffer . append ( ManagementConstants . BUS_ID_PROP ) . append ( '=' ) . append ( bus . getId ( ) ) . append ( ',' ) ; buffer . append ( "WorkQueueManager=" ) . append ( NAME_VALUE ) ; buffer . append ( ',' ) . append ( ManagementConstants . TYPE_PROP ) . append ( '=' ) . append ( TYPE_VALUE ) . append ( ',' ) ; buffer . append ( ManagementConstants . INSTANCE_ID_PROP ) . append ( '=' ) . append ( wqManager . hashCode ( ) ) ; return new ObjectName ( buffer . toString ( ) ) ; } }